// Compliant: Complete if-else-if with final else
void process_grade(int score) {
    if (score >= 90) {
        cout << "A";
    } else if (score >= 80) {
        cout << "B";
    } else if (score >= 70) {
        cout << "C";
    } else {
        cout << "F";  // Handles all other cases
    }
}

// Compliant: Default case with appropriate action
void handle_error(int error_code) {
    if (error_code == 1) {
        handle_network_error();
    } else if (error_code == 2) {
        handle_file_error();
    } else if (error_code == 3) {
        handle_memory_error();
    } else {
        log_unknown_error(error_code);
        throw std::runtime_error("Unknown error code");
    }
}
